    public override object parseTrade(object rawTrade, object market = null)
    {
        object trade = this.safeTrade(this.extend(new Dictionary<string, object>() {
            { "info", rawTrade },
        }, rawTrade));
        ((IDictionary<string,object>)trade)["id"] = "";
        ((IDictionary<string,object>)trade)["order"] = null;
        ((IDictionary<string,object>)trade)["takerOrMaker"] = null;
        ((IDictionary<string,object>)trade)["timestamp"] = this.safeInteger(rawTrade, "timestamp");
        return trade;
    }

