            { "info", response },
        };
        object balances = this.safeDict(response, "balances", new List<object>() {});
        object currencies = new List<object>(((IDictionary<string,object>)balances).Keys);
        for (object i = 0; isLessThan(i, getArrayLength(currencies)); postFixIncrement(ref i))
        {
            object code = getValue(currencies, i);
            object balance = getValue(balances, code);
            object account = this.account();
            ((IDictionary<string,object>)account)["free"] = this.safeString(balance, "free");
            ((IDictionary<string,object>)account)["used"] = this.safeString(balance, "used");
            ((IDictionary<string,object>)account)["total"] = this.safeString(balance, "total");
            ((IDictionary<string,object>)result)[(string)code] = account;
        }
        object timestamp = this.safeInteger(response, "timestamp");
        ((IDictionary<string,object>)result)["timestamp"] = timestamp;
        ((IDictionary<string,object>)result)["datetime"] = this.iso8601(timestamp);
        return this.safeBalance(result);
    }

