     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {bool} [params.reduceOnly] true or false whether the order is reduce-only
     * @param {Account} [params.account] account id to use, required
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/#/?id=order-structure}
     */
    public async override Task<object> createOrder(object symbol, object type, object side, object amount, object price = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadMarkets();
        object account = null;
        var accountparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "account");
        account = ((IList<object>)accountparametersVariable)[0];
        parameters = ((IList<object>)accountparametersVariable)[1];
        object order = this.parseCreateEditOrderArgs(null, symbol, type, side, amount, price, parameters);
        object orders = await this.createOrders(new List<object>() {((object)order)}, new Dictionary<string, object>() {
            { "account", account },
        });
        return getValue(orders, 0);
    }

    /**
     * @method
     * @name aftermath#createOrders
     * @see https://testnet.aftermath.finance/docs/#/CCXT/build_create_orders
     * @see https://testnet.aftermath.finance/docs/#/CCXT/submit_create_orders
     * @description create a list of trade orders
     * @param {Array} orders list of orders to create, each object should contain the parameters required by createOrder, namely symbol, type, side, amount, price and params
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {Account} [params.account] account id to use, required
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/#/?id=order-structure}
     */
    public async override Task<object> createOrders(object orders, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadMarkets();
        object ordersRequest = new List<object>() {};
        for (object i = 0; isLessThan(i, getArrayLength(orders)); postFixIncrement(ref i))
        {
            object order = this.clone(getValue(orders, i));
            object symbol = this.safeString(order, "symbol");
            object market = this.market(symbol);
            object price = this.safeString(order, "price");
            object amount = this.safeString(order, "amount");
            object orderParams = this.safeDict(order, "params", new Dictionary<string, object>() {});
            object reduceOnly = this.safeBool(orderParams, "reduceOnly");
            if (isTrue(!isEqual(reduceOnly, null)))
            {
                ((IDictionary<string,object>)order)["reduceOnly"] = reduceOnly;
            }
            ((IDictionary<string,object>)order).Remove((string)"symbol");
            ((IDictionary<string,object>)order).Remove((string)"params");
            ((IDictionary<string,object>)order)["chId"] = getValue(market, "id");
            if (isTrue(!isEqual(price, null)))
            {
                ((IDictionary<string,object>)order)["price"] = this.parseToNumeric(this.priceToPrecision(symbol, price));
            }
            ((IDictionary<string,object>)order)["amount"] = this.parseToNumeric(this.amountToPrecision(symbol, amount));
            ((IList<object>)ordersRequest).Add(order);
        }
        object account = null;
        var accountparametersVariable = this.handleOptionAndParams(parameters, "createOrders", "account");
        account = ((IList<object>)accountparametersVariable)[0];
        parameters = ((IList<object>)accountparametersVariable)[1];
        object txRequest = new Dictionary<string, object>() {
            { "accountId", account },
            { "metadata", new Dictionary<string, object>() {
                { "sender", this.walletAddress },
            } },
            { "orders", ordersRequest },
            { "deallocateFreeCollateral", false },
        };
        object tx = await this.privatePostBuildCreateOrders(this.extend(txRequest, parameters));
        object request = this.signTxEd25519(tx);
        object response = await this.privatePostSubmitCreateOrders(request);
        //
        // [
        //     {
        //         "id": "340282366919093604570116171100942992979",
        //         "datetime": "2025-04-10 10:38:39.323 UTC",
        //         "timestamp": 1744281519323,
        //         "status": "open",
        //         "symbol": "BTC/USD:USDC",
        //         "type": "limit",
        //         "side": "buy",
        //         "price": 10001.0,
        //         "average": 0.0,
        //         "amount": 0.01,
        //         "filled": 0.0,
        //         "remaining": 0.01,
        //         "cost": 0.0,
        //         "trades": [],
        //         "fee": {}
        //     }
        // ]
        //
        return this.parseOrders(response);
    }

