     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {Account} [params.account] account id to use, required
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/#/?id=transaction-structure}
     */
    public async override Task<object> withdraw(object code, object amount, object address, object tag = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        await this.loadMarkets();
        object currency = this.currency(code);
        object account = null;
        var accountparametersVariable = this.handleOptionAndParams(parameters, "withdraw", "account");
        account = ((IList<object>)accountparametersVariable)[0];
        parameters = ((IList<object>)accountparametersVariable)[1];
        if (isTrue(isEqual(account, null)))
        {
            throw new ArgumentsRequired ((string)add(this.id, " withdraw() requires a account parameter in params")) ;
        }
        object txRequest = new Dictionary<string, object>() {
            { "accountId", account },
            { "metadata", new Dictionary<string, object>() {
                { "sender", this.walletAddress },
            } },
            { "amount", amount },
        };
        object tx = await this.privatePostBuildWithdraw(txRequest);
        object request = this.signTxEd25519(tx);
        object response = await this.privatePostSubmitWithdraw(request);
        //
        // {
        //     "id": "0xf93f9bb8bf97eb570410caada92cfa3e66c7ed3a203a164f51d22d41eabe09c0",
        //     "type": "subaccount",
        //     "code": "USDC",
        //     "accountNumber": 101,
        //     "collateral": 39.0
        // }
        //
        return this.extend(this.parseTransaction(response, currency), new Dictionary<string, object>() {
            { "addressFrom", account },
            { "amount", amount },
        });
    }

