    /**
     * @method
     * @name aftermath#signTxEd25519
     * @description Helper to sign some transaction bytes and return a generic transaction execution request.
     * @param {object} [tx] transaction bytes and the signing digest for them
     * @returns {object} the input transaction bytes and the signed digest
     */
    public virtual object signTxEd25519(object tx)
    {
        if (isTrue(isGreaterThanOrEqual(getIndexOf(this.privateKey, "suiprivkey"), 0)))
        {
            throw new NotSupported ((string)add(this.id, " only support hex encoding private key, please transform bech32 encoding private key")) ;
        }
        object signingDigest = this.safeString(tx, "signingDigest");
        object digest = this.base64ToBinary(signingDigest);
        object privateKey = this.base16ToBinary(this.privateKey);
        object signature = eddsa(digest, privateKey, ed25519);
        object hexPublicKey = this.safeString(this.options, "publicKey");
        if (isTrue(isEqual(hexPublicKey, null)))
        {
            throw new ArgumentsRequired ((string)add(this.id, " requires hex encoding public key in options")) ;
        }
        object publicKey = this.base16ToBinary(hexPublicKey);
        object suiSignature = this.binaryConcat(this.base16ToBinary("00"), this.binaryConcat(this.base64ToBinary(signature), publicKey));
        object base64Sig = this.binaryToBase64(suiSignature);
        object transactionBytes = this.safeString(tx, "transactionBytes");
        object signatures = new List<object>() {base64Sig};
        return new Dictionary<string, object>() {
            { "transactionBytes", transactionBytes },
            { "signatures", signatures },
        };
    }

    public override object parseOrder(object order, object market = null)
    {
        return this.safeOrder(order, market);
    }

    public override object handleErrors(object httpCode, object reason, object url, object method, object headers, object body, object response, object requestHeaders, object requestBody)
    {
        if (!isTrue(response))
        {
            return null;  // fallback to default error handler
        }
        //
        // Error with ID: #68498f1e536664f31a7b1aa7
        //
        if (isTrue(isGreaterThanOrEqual(getIndexOf(body, "Error"), 0)))
        {
            this.throwBroadlyMatchedException(getValue(this.exceptions, "broad"), body, "");
            throw new ExchangeError ((string)body) ;
        }
        return null;
    }

    public override object sign(object path, object api = null, object method = null, object parameters = null, object headers = null, object body = null)
    {
        api ??= "public";
        method ??= "POST";
        parameters ??= new Dictionary<string, object>();
        object url = add(add(getValue(getValue(this.urls, "api"), "rest"), "/"), path);
        if (isTrue(isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
        }
        if (isTrue(isEqual(method, "POST")))
        {
            headers = new Dictionary<string, object>() {
                { "Content-Type", "application/json" },
            };
            body = this.json(parameters);
        }
        return new Dictionary<string, object>() {
            { "url", url },
            { "method", method },
            { "body", body },
            { "headers", headers },
        };
    }
